declare module '*.module.scss' {
    const classes: any;
    export default classes;
}

declare module '*.scss' {
    const content: void;
    export default content;
}

declare module '*.svg' {
    const content: string;
    export default content;
}

declare module '*.jpg' {
    const content: string;
    export default content;
}

declare module '*.png' {
    const content: string;
    export default content;
}

declare module '*.webp' {
    const content: string;
    export default content;
}